head.script:
tailwind.config = {
  theme: {
    extend: {
      fontFamily: {
        sans: ['Inter', 'sans-serif'],
        display: ['Space Grotesk', 'sans-serif'],
        mono: ['JetBrains Mono', 'monospace'],
      },
    }
  }
}

head.b:skin:
body {
  margin: 0;
  padding: 0;
  background-color: #f8fafc;
  font-family: 'Inter', sans-serif;
}
.no-scrollbar::-webkit-scrollbar {
  display: none;
}
.no-scrollbar {
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.section, .widget {
  margin: 0;
  padding: 0;
}
.status-msg-wrap {
  display: none !important;
}
.post-body img {
  max-width: 100%;
  height: auto;
  border-radius: 0.75rem;
  margin: 0.5rem auto;
  display: block;
}

body.script:
//
const CLOUDINARY_CLOUD_NAME = "dr070zmrm";

// Dynamic tag matching styling rules of getTagColor helper inside app
const TAG_COLOR_MAPPING = {
  'DEVELOPER': 'bg-purple-600',
  'AI': 'bg-emerald-600',
  'VIRAL': 'bg-rose-600',
  'TECH': 'bg-sky-600',
  'TECHNOLOGY': 'bg-sky-600',
  'DESIGN': 'bg-amber-500',
  'NEWS': 'bg-slate-900',
  'STORY': 'bg-slate-900',
  'TRENDS': 'bg-blue-600',
  'FOOTBALL': 'bg-green-600',
  'BUSINESS': 'bg-amber-500'
};

function dynamicColorTags() {
  const tagContainers = document.querySelectorAll('.uppercase-tag');
  tagContainers.forEach(tag => {
    const rawLabel = tag.getAttribute('data-label') || tag.innerText || 'STORY';
    const normalized = rawLabel.trim().toUpperCase();

    let colorClass = 'bg-slate-900'; // Fallback default grey background
    if (TAG_COLOR_MAPPING[normalized]) {
      colorClass = TAG_COLOR_MAPPING[normalized];
    } else {
      const colors = ['bg-indigo-600', 'bg-blue-600', 'bg-teal-600', 'bg-pink-600'];
      let hashCode = 0;
      for (let i = 0; i < normalized.length; i++) {
        hashCode = normalized.charCodeAt(i) + ((hashCode << 5) - hashCode);
      }
      const index = Math.abs(hashCode) % colors.length;
      colorClass = colors[index];
    }

    tag.className = tag.className.replace(/bg-\w+-\d+/g, '').trim() + ' ' + colorClass;
  });
}

// Auto Optimizer Cloudinary Handler
function optimizeAllBloggerImages() {
  const images = document.querySelectorAll('.dynamic-cloudinary');
  images.forEach(img => {
    const original = img.getAttribute('data-original-src') || img.src || '';
    if (original && !original.includes('cloudinary.com') && original.startsWith('http')) {
      img.src = `https://res.cloudinary.com/${CLOUDINARY_CLOUD_NAME}/image/fetch/f_auto,q_auto,w_400,c_fill,g_auto/${original}`;
    }
  });
}

// Toggle Blogger dynamic search input drawer
function toggleSearchBox() {
  const box = document.getElementById('search-box-container');
  if (box.classList.contains('hidden')) {
    box.classList.remove('hidden');
  } else {
    box.classList.add('hidden');
  }
}

// Modern styled toast popup helper matching Next.js styling
function showToastNotification(msg) {
  const toast = document.getElementById('custom-toast');
  toast.innerText = msg;
  toast.classList.remove('opacity-0', 'scale-95');
  toast.classList.add('opacity-100', 'scale-100');

  setTimeout(() => {
    toast.classList.remove('opacity-100', 'scale-100');
    toast.classList.add('opacity-0', 'scale-95');
  }, 2500);
}

// Copying dynamic Blogspot current post URL to clipboard
function copyPostLink() {
  const currentUrl = window.location.href;
  navigator.clipboard.writeText(currentUrl).then(() => {
    showToastNotification("Link copied to clipboard!");
  }).catch(() => {
     const tempInput = document.createElement("input");
     tempInput.value = currentUrl;
     document.body.appendChild(tempInput);
     tempInput.select();
     document.execCommand("copy");
     document.body.removeChild(tempInput);
     showToastNotification("Link copied to clipboard!");
  });
}

// Double tab / love like simulation
let blogspotLovedState = false;
function handleBloggerLike() {
  const parentUrl = window.location.pathname;
  const key = "is_liked_map_" + btoa(parentUrl);
  const statusText = document.getElementById('b-like-status');
  const heartIcon = document.getElementById('heart-icon');

  if (!blogspotLovedState) {
    blogspotLovedState = true;
    statusText.innerText = "Loved!";
    statusText.className = "text-[8px] font-bold font-mono text-red-600 animate-pulse";
    heartIcon.classList.remove('text-slate-400');
    heartIcon.classList.add('text-red-500');
    heartIcon.setAttribute('fill', 'currentColor');
    localStorage.setItem(key, "true");
    showToastNotification("Added to Liked stories!");
    triggerSystemPushNotification("Community Event", "You loved a story: '" + (document.querySelector('h1')?.innerText || 'Article') + "'");
  } else {
    blogspotLovedState = false;
    statusText.innerText = "Love";
    statusText.className = "text-[8px] font-bold font-mono text-slate-600";
    heartIcon.classList.remove('text-red-500');
    heartIcon.classList.add('text-slate-400');
    heartIcon.removeAttribute('fill');
    localStorage.removeItem(key);
    showToastNotification("Removed from Liked stories");
  }
}

// Double-feature Bookmarking Core & Interactive bottom drawer synchronizer
let isBloggerDrawerOpen = false;
function toggleBloggerBookmarkDrawer() {
  const drawer = document.getElementById('bookmarks-drawer');
  const navBtn = document.getElementById('nav-bookmark-btn');

  // Close other drawers
  document.getElementById('categories-drawer').classList.add('translate-y-full');
  document.getElementById('notifications-drawer').classList.add('translate-y-full');
  document.getElementById('sharing-drawer').classList.add('translate-y-full');

  if (!isBloggerDrawerOpen) {
    isBloggerDrawerOpen = true;
    drawer.classList.remove('translate-y-full');
    navBtn.classList.remove('text-slate-300', 'text-slate-400');
    navBtn.classList.add('text-slate-950');
    renderBloggerBookmarksList();
  } else {
    isBloggerDrawerOpen = false;
    drawer.classList.add('translate-y-full');
    navBtn.classList.remove('text-slate-950');
    navBtn.classList.add('text-slate-400');
  }
}

// Bookmark list generator
function renderBloggerBookmarksList() {
  const container = document.getElementById('bookmarks-items-list');
  const items = [];

  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key.startsWith('bookmark_map_')) {
      try {
        const artData = JSON.parse(localStorage.getItem(key));
        items.push(artData);
      } catch(e) { console.error("Bad storage load", e); }
    }
  }

  // Update counters profile
  const profCount = document.getElementById('profile-bookmark-count-val');
  if (profCount) profCount.innerText = items.length;

  if (items.length === 0) {
    container.innerHTML = `
      <div class="text-center py-12">
        <p class="text-slate-400 text-[9px] font-bold uppercase tracking-widest leading-relaxed">No Bookmarks Pinned</p>
        <p class="text-slate-400 text-[8px] mt-1 leading-normal px-6">Articles you bookmark from post pages will appear inside this frame.</p>
      </div>
    `;
    return;
  }

  let htmlOutput = '<div class="space-y-3">';
  items.forEach(item => {
    htmlOutput += `
      <div class="flex items-center justify-between border-b border-slate-50 pb-2.5 last:border-0 last:pb-0">
        <a href="${item.url}" class="flex-1 min-w-0 pr-3">
          <h5 class="text-[10px] font-bold text-slate-100 text-slate-950 tracking-tight leading-snug line-clamp-2 hover:text-blue-600 transition-colors">${item.title}</h5>
          <p class="text-[7.5px] font-mono text-slate-400 mt-1 uppercase tracking-wider">${item.label ? item.label : 'STORY'}</p>
        </a>
        <button class="text-rose-500 hover:text-rose-700 p-1.5 bg-rose-50 hover:bg-rose-100 rounded-md transition-colors" onclick="removeIndexedBookmark('${item.url}')">
          <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
        </button>
      </div>
    `;
  });
  htmlOutput += '</div>';
  container.innerHTML = htmlOutput;
}

function removeIndexedBookmark(targetUrl) {
  const key = "bookmark_map_" + btoa(targetUrl);
  localStorage.removeItem(key);
  showToastNotification("Story unpinned successfully");
  renderBloggerBookmarksList();

  // Check if current details bookmark status matches
  if (window.location.pathname === targetUrl) {
    blogspotBookmarkState = false;
    const bookmarkIcon = document.getElementById('nav-bookmark-icon');
    if (bookmarkIcon) {
      bookmarkIcon.removeAttribute('fill');
      bookmarkIcon.classList.remove('text-slate-950');
    }
  }
}

// Bookmark core status simulator
let blogspotBookmarkState = false;
function toggleBloggerBookmark() {
  const targetUrl = window.location.pathname;
  const key = "bookmark_map_" + btoa(targetUrl);
  const postTitle = document.querySelector('h1')?.innerText || 'Yondaime Core Story';
  const rawLabels = document.querySelector('.uppercase-tag')?.innerText || 'STORY';
  const bookmarkIcon = document.getElementById('nav-bookmark-icon');

  if (!blogspotBookmarkState) {
    blogspotBookmarkState = true;
    bookmarkIcon.setAttribute('fill', 'currentColor');
    bookmarkIcon.classList.add('text-slate-950');

    const saveItem = {
      url: targetUrl,
      title: postTitle,
      label: rawLabels
    };
    localStorage.setItem(key, JSON.stringify(saveItem));
    showToastNotification("Pinned to Bookmarks folder!");
    triggerSystemPushNotification("Bookmark Sync", "Added story: '" + postTitle.substring(0, 25) + "...'");
  } else {
    blogspotBookmarkState = false;
    bookmarkIcon.removeAttribute('fill');
    bookmarkIcon.classList.remove('text-slate-950');
    localStorage.removeItem(key);
    showToastNotification("Bookmark storage unpinned");
  }
}

// Dynamic Categories Drawer toggler
let isBloggerCategoriesOpen = false;
function toggleBloggerCategoriesDrawer() {
  const drawer = document.getElementById('categories-drawer');
  const navBtn = document.getElementById('nav-categories-btn');

  // Close other drawers
  document.getElementById('bookmarks-drawer').classList.add('translate-y-full');
  document.getElementById('notifications-drawer').classList.add('translate-y-full');
  document.getElementById('sharing-drawer').classList.add('translate-y-full');
  isBloggerDrawerOpen = false;

  if (!isBloggerCategoriesOpen) {
    isBloggerCategoriesOpen = true;
    drawer.classList.remove('translate-y-full');
    navBtn.classList.remove('text-slate-400');
    navBtn.classList.add('text-slate-950');
  } else {
    isBloggerCategoriesOpen = false;
    drawer.classList.add('translate-y-full');
    navBtn.classList.remove('text-slate-950');
    navBtn.classList.add('text-slate-400');
  }
}

// Dynamic Profile Modal Dialogue toggler
function toggleBloggerProfilePopup() {
  const modal = document.getElementById('profile-dialog-box');

  // Update bookmark totals on open
  let totalPinned = 0;
  for(let i=0; i<localStorage.length; i++) {
    if(localStorage.key(i).startsWith('bookmark_map_')) totalPinned++;
  }
  const profCount = document.getElementById('profile-bookmark-count-val');
  if (profCount) profCount.innerText = totalPinned;

  if (modal.classList.contains('hidden')) {
    modal.classList.remove('hidden');
  } else {
    modal.classList.add('hidden');
  }
}

// SYSTEM NOTIFICATION SIMULATION ENGINE (Highly customized and synchronized)
function toggleNotificationsPanel() {
  const drawer = document.getElementById('notifications-drawer');
  const badgeDot = document.getElementById('notif-dot');

  // Close other drawers
  document.getElementById('bookmarks-drawer').classList.add('translate-y-full');
  document.getElementById('categories-drawer').classList.add('translate-y-full');
  document.getElementById('sharing-drawer').classList.add('translate-y-full');
  isBloggerDrawerOpen = false;
  isBloggerCategoriesOpen = false;

  if (drawer.classList.contains('translate-y-full')) {
    drawer.classList.remove('translate-y-full');
    badgeDot.classList.add('hidden'); // Clear notifications visual alert
    renderBloggerNotificationsHub();
  } else {
    drawer.classList.add('translate-y-full');
  }
}

// Push new alerts securely 
let notificationStorage = [
  { id: 1, title: "Engine Boosted", text: "Cloudinary Dynamic Delivery caching has been established successfully.", time: "Just now" },
  { id: 2, title: "Sitemaps Integrated", text: "Index standard RSS Sitemap has successfully piped into search engines maps.", time: "10m ago" },
  { id: 3, title: "Welcome!", text: "Thank you for migrating to the ultra-high fidelity Yondaime Blogger engine built in 2026.", time: "1h ago" }
];

function triggerSystemPushNotification(title, msg) {
  notificationStorage.unshift({
    id: Date.now(),
    title: title,
    text: msg,
    time: "Just now"
  });

  // Show alerts visual dot dot
  const badgeDot = document.getElementById('notif-dot');
  if (badgeDot) badgeDot.classList.remove('hidden');
  showToastNotification(`🔔 ${title}: ${msg.substring(0, 20)}...`);
}

function renderBloggerNotificationsHub() {
  const container = document.getElementById('notifications-list-container');
  if (notificationStorage.length === 0) {
    container.innerHTML = `
      <div class="text-center py-10">
        <p class="text-slate-400 text-[10px] uppercase font-bold tracking-widest">No Notifications</p>
      </div>
    `;
    return;
  }

  let out = '<div class="space-y-2.5">';
  notificationStorage.forEach(item => {
    out += `
      <div class="p-3 bg-slate-50 border border-slate-100 rounded-xl space-y-1">
        <div class="flex justify-between items-center">
          <span class="text-[9.5px] font-extrabold text-slate-900">${item.title}</span>
          <span class="text-[7.5px] text-slate-400 font-mono">${item.time}</span>
        </div>
        <p class="text-[8.5px] text-slate-600 leading-normal">${item.text}</p>
      </div>
    `;
  });
  out += '</div>';
  container.innerHTML = out;
}

// Dynamic Follow interaction
let followerStatusSimulated = false;
function toggleFollowStateBlogger() {
  const btn = document.getElementById('follower-badge-btn');
  if (!btn) return;
  if (!followerStatusSimulated) {
    followerStatusSimulated = true;
    btn.innerText = "FOLLOWED ✓";
    btn.className = "bg-slate-100 text-slate-700 border border-slate-300 text-[8px] font-extrabold px-3 py-1.5 rounded-full transition-all";
    showToastNotification("You are now following this author!");
    triggerSystemPushNotification("Author Hub", "Followed author: " + (document.querySelector('.font-bold.text-slate-950.leading-none')?.innerText || 'Kenji'));
  } else {
    followerStatusSimulated = false;
    btn.innerText = "+ FOLLOW";
    btn.className = "bg-blue-600 hover:bg-blue-700 text-white text-[8px] font-extrabold px-3 py-1.5 rounded-full transition-all";
    showToastNotification("Author un-followed successfully.");
  }
}

// STAR RATINGS POPUP SIMULATOR 
function triggerStarRatingPopup() {
  showToastNotification("⭐️ Thank you! You rated this story 5 Stars!");
  triggerSystemPushNotification("Dynamic Ratings", "Submitted 5-Star review rating successfully!");
}

// ANONYMOUS SLIDER THREAD CREATION
let isThreadBoxOpen = false;
function triggerThreadPopup() {
  const box = document.getElementById('general-modal-threads');
  if (box.classList.contains('hidden')) {
    box.classList.remove('hidden');
  } else {
    box.classList.add('hidden');
  }
}

function submitThreadAnonymous() {
  const topicInput = document.getElementById('thread-anonymous-topic');
  const bodyInput = document.getElementById('thread-anonymous-body');

  if (!bodyInput.value.trim()) {
    showToastNotification("Thread message content cannot be empty.");
    return;
  }

  showToastNotification("Your anonymous thread is posted successfully!");
  triggerSystemPushNotification("Thread Contribution", "Post created: '" + (topicInput.value || "Discussion") + "...'");

  // Clear inputs
  topicInput.value = "";
  bodyInput.value = "";
  triggerThreadPopup();
}

// SHARING UTILITIES CONTROLLER
function openBloggerSharingDrawer() {
  const drawer = document.getElementById('sharing-drawer');
  const linkBox = document.getElementById('share-link-input-field');
  const currentLoc = window.location.href;

  // Close other drawers
  document.getElementById('bookmarks-drawer').classList.add('translate-y-full');
  document.getElementById('categories-drawer').classList.add('translate-y-full');
  document.getElementById('notifications-drawer').classList.add('translate-y-full');
  isBloggerDrawerOpen = false;

  linkBox.value = currentLoc;

  // Dynamic mapping href socials
  document.getElementById('share-wa-link').href = `https://api.whatsapp.com/send?text=${encodeURIComponent(currentLoc)}`;
  document.getElementById('share-fb-link').href = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(currentLoc)}`;
  document.getElementById('share-tw-link').href = `https://twitter.com/intent/tweet?url=${encodeURIComponent(currentLoc)}`;
  document.getElementById('share-tg-link').href = `https://telegram.me/share/url?url=${encodeURIComponent(currentLoc)}`;

  drawer.classList.remove('translate-y-full');
}

function closeBloggerSharingDrawer() {
  document.getElementById('sharing-drawer').classList.add('translate-y-full');
}

function copyPostLinkInsideDrawer() {
  const linkBox = document.getElementById('share-link-input-field');
  navigator.clipboard.writeText(linkBox.value).then(() => {
    showToastNotification("Link copied to clipboard!");
    closeBloggerSharingDrawer();
  });
}

// COMMENT SECTION LIVE SYSTEM FOR INDIVIDUAL POSTS (Mimics real-time syncing)
let commentStorage = [
  { author: "Kenji Sato", date: "June 08, 2026", text: "Distributed micro-kernels are absolutely the future of portable edge systems. This is a very clean breakdown on Blogger integration workflow." },
  { author: "Ahmad_Dev", date: "June 08, 2026", text: "Desain temanya cantik, presisi responsif rasionya mirip sekali dengan framework nextjs murni. Mantap!" },
  { author: "Michael", date: "June 07, 2026", text: "Bookmarks feature is fully working on local state, epic Blogger theme code!" }
];

function handleSendBloggerComment(event) {
  event.preventDefault();
  const nameBox = document.getElementById('commentor-name-box');
  const bodyBox = document.getElementById('commentor-body-box');

  if (!bodyBox.value.trim()) return;

  const commenterName = nameBox.value.trim() || "Anonymous Guest";

  // Unshift to local state
  commentStorage.unshift({
    author: commenterName,
    date: "June 08, 2026",
    text: bodyBox.value.trim()
  });

  bodyBox.value = ""; // Clear Input
  showToastNotification("Comment posted successfully!");
  triggerSystemPushNotification("New Comment", `${commenterName} left a comment: '${commentStorage[0].text.substring(0, 15)}...'`);
  renderDynamicBloggerComments();
}

function renderDynamicBloggerComments() {
  const container = document.getElementById('dyn-blogger-comments-list');
  const counterVal = document.getElementById('comments-header-counter-val');

  if (!container) return; // Exit if multiple posts list view (homepage)

  if (counterVal) counterVal.innerText = commentStorage.length;

  let htmlVal = '<div class="space-y-3.5 pt-2">';
  commentStorage.forEach(comment => {
    htmlVal += `
      <div class="bg-slate-50 border border-slate-100 p-3 rounded-xl flex space-x-2.5 items-start">
        <div class="w-6 h-6 rounded-full bg-slate-200 border border-slate-300 flex items-center justify-center font-bold text-slate-700 text-[9px] shrink-0 font-display">
          ${comment.author.substring(0, 2).toUpperCase()}
        </div>
        <div class="flex-1 min-w-0">
          <div class="flex items-center justify-between">
            <span class="text-[9px] font-extrabold text-slate-950">${comment.author}</span>
            <span class="text-[7.5px] font-mono text-slate-400">${comment.date}</span>
          </div>
          <p class="text-[9px] text-slate-700 leading-normal mt-1 pr-1" style="word-break: break-all;">${comment.text}</p>
        </div>
      </div>
    `;
  });
  htmlVal += '</div>';
  container.innerHTML = htmlVal;
}

// Dynamic Clock ticking helper
function updateClockTimeBlogger() {
  const badge = document.getElementById('visitor-clock');
  if (!badge) return;
  const now = new Date();
  const stringVal = now.toISOString().substring(11, 16) + " UTC";
  badge.innerText = stringVal;
}

// Set Active bottom tab highlights
function setupActiveStates() {
  const currentLoc = window.location.href;
  const homeBtn = document.getElementById('nav-home-btn');

  // Default to highlighting Home button
  if (homeBtn) {
    homeBtn.className = homeBtn.className.replace('text-slate-400', 'text-slate-950');
  }

  // Read current horizontal active link
  const links = document.querySelectorAll('.tab-item');
  links.forEach(lnk => {
    if (currentLoc.includes(lnk.getAttribute('href'))) {
      lnk.className = lnk.className + ' text-slate-950 border-b-2 border-slate-950 pb-1.5';
    }
  });
}

// Initialize individual States dynamically on DOM load
window.addEventListener("DOMContentLoaded", () => {
  const currentUrl = window.location.pathname;
  const likeKey = "is_liked_map_" + btoa(currentUrl);
  const bookmarkKey = "bookmark_map_" + btoa(currentUrl);

  // Trigger Cloudinary optimizer pipeline
  optimizeAllBloggerImages();

  // Trigger standard responsive tags coloring mapping
  dynamicColorTags();

  // Setup dynamic active tab indicator colors
  setupActiveStates();

  // Comments loader
  renderDynamicBloggerComments();

  // Run dynamic clock
  updateClockTimeBlogger();
  setInterval(updateClockTimeBlogger, 60000);

  // Initial Notification setup alert
  setTimeout(() => {
    const badgeDot = document.getElementById('notif-dot');
    if (badgeDot) badgeDot.classList.remove('hidden');
  }, 5000);

  // Check local Likes state
  if (localStorage.getItem(likeKey) === "true") {
    blogspotLovedState = true;
    const statusText = document.getElementById('b-like-status');
    const heartIcon = document.getElementById('heart-icon');
    if (statusText && heartIcon) {
      statusText.innerText = "Loved!";
      statusText.className = "text-[8px] font-black font-mono text-red-650";
      heartIcon.classList.remove('text-slate-400');
      heartIcon.classList.add('text-red-500');
      heartIcon.setAttribute('fill', 'currentColor');
    }
  }

  // Check bookmark pins
  if (localStorage.getItem(bookmarkKey)) {
    blogspotBookmarkState = true;
    const bookmarkIcon = document.getElementById('nav-bookmark-icon');
    if (bookmarkIcon) {
      bookmarkIcon.setAttribute('fill', 'currentColor');
      bookmarkIcon.classList.add('text-slate-950');
    }
  }
});
//
